{"code": "import json

# Load Europe metadata
europe_file = locals()['var_functions.query_db:6']
with open(europe_file, 'r') as f:
    europe_metadata = json.load(f)

# Group article IDs by year for efficient querying
article_ids_by_year = {}
total_ids = []

for article in europe_metadata:
    article_id = article['article_id']
    year = article['publication_date'][:4]
    if int(year) >= 2010 and int(year) <= 2020:
        total_ids.append(article_id)
        if year not in article_ids_by_year:
            article_ids_by_year[year] = []
        article_ids_by_year[year].append(article_id)

print('__RESULT__:')
print(json.dumps({
    'years': list(article_ids_by_year.keys()),
    'total_ids_2010_2020': len(total_ids),
    'articles_per_year': {year: len(ids) for year, ids in article_ids_by_year.items()}
}))"}
